const albQuotes = (section.match(/class=\"alberdi-quote/g) || []).length;
check('>=3 alberdi-quote standalone blocks', albQuotes >= 3);

// 4. Images - each card
const cardImages = (section.match(/class=\"card-image\"/g) || []).length;
check('20 card images (all cards)', cardImages === 20);

// 5. Opinión cards have blockquote + attribution
const opinionCards = (section.match(/data-certeza=\"opinion\"/g) || []).length;
const blockquotes = (section.match(/<blockquote/g) || []).length;
check('5 opinión cards', opinionCards === 5);
check('>=5 blockquotes (one per opinión minimum)', blockquotes >= 5);

// 6. Sub-navigation
check('Sub-nav present', section.includes('class=\"sub-nav\"'));
const subNavLinks = (section.match(/class=\"sub-nav__link/g) || []).length;
check('4 sub-nav links', subNavLinks >= 4);
['rev-1800-1820','rev-1820-1835','rev-1835-1852','rev-1852-1860'].forEach(id => {
  check('Sub-period ID: ' + id, html.includes('id=\"' + id + '\"'));
});

