check('revolucion-timeline present', section.includes('revolucion-timeline'));
const markers = (html.match(/<div class=\"revolucion-timeline__marker/g) || []).length;
check('10 timeline markers', markers === 10);
check('Timeline fires via reveal class', section.includes('revolucion-timeline reveal'));

